#include <stdio.h>
#include <stdlib.h>

int main() {
    FILE *izlaz;
    char niz[] = "Uvod u programiranje";
    int i;

    izlaz = fopen("datoteka.txt", "w");
    if (izlaz == NULL) {
        printf("Otvaranje datoteke datoteka.txt nije uspjelo!\n");
        return 1;
    }

    for (i = 0; niz[i] != '\0'; i++) {
        fputc(niz[i], izlaz);
        if (ferror(izlaz)) {
            printf("Greska prilikom upisa.\n");
            break;
        }
    }

    printf("Upis zavrsen.\n");
    fclose(izlaz);
    return 0;
}
